+    
+    for (rendered.pixels) |row| {
+        for (row) |pixel| {
+            const gray = if (pixel == 1) 0 else if (pixel == 2) 128 else 255;
+            try writer.print("{d} ", .{gray});
+        }
+        try writer.print("\n", .{});
+    }
+    
+    std.debug.print("✅ /tmp/test.pgm\n", .{});
